void loadBuffer(uint8_t value) {  //Loads ASCII value from string to back buffer
  //load a space 
  for (uint8_t j = 0; j < CHAR_HEIGHT; j++)
  {
    backBuffer[0][j] = 0;
    backBuffer[1][j] = 0;
    backBuffer[2][j] = 0;
    backBuffer[3][j] = 0;
  }

  for (uint8_t i = 0; i < (CHAR_WIDTH - OFFSET) * 4; i++)
  {
    for (uint8_t j = 0; j < CHAR_HEIGHT; j++)
    {
      backBuffer[i + 4][j] = font[value][(i / 4)][j];
    }
  }
}

void load_leds()
{
  for (uint8_t x = 0; x < NUM_COLS; x++)
  {
    for (uint8_t y = 0; y < CHAR_HEIGHT; y ++)
    {
      if (toDisplay[x][y])
      {
        matrix->drawPixel(x, y, matrix->Color(red, green, blue));
      }
      else
      {
        matrix->drawPixel(x, y, matrix->Color(0, 0, 0));
      }
    }
  }
}

void scroll()
{
  for (uint8_t shift = 0; shift < (CHAR_WIDTH - OFFSET) * 4 + 4; shift++)
  {

    for (uint8_t i = 1; i < NUM_COLS; i++)
    {
      for (uint8_t j = 0; j < CHAR_HEIGHT; j++)
      {
        toDisplay[i - 1][j] = toDisplay[i][j];
        backBuffer[i - 1][j] = backBuffer[i][j];
      }
    }

    for (uint8_t j = 0; j < CHAR_HEIGHT; j++)
    {
      toDisplay[NUM_COLS - 1][j] = backBuffer[0][j];
      backBuffer[NUM_COLS - 1][j] = 0;
    }

    load_leds();
    if ((shift % 4) - 2 == 0)
    {
      matrix->show();
      delay(scroll_speed);
    }
  }
}

void scroll_text(String message)
{

  message = message + "  ";

  matrix->setBrightness(brightness);
  uint8_t value = message.charAt(pointer);
  value = value - 32;
  if (value >= 65 && value <= 90)
  {
    OFFSET = DIFF_LOWERCASE;
  }
  else
  {
    OFFSET = 0;
  }
  loadBuffer(value);
  scroll();
  pointer = (pointer + 1) % message.length(); //Increment pointer, pointer =< message length
}

void show_image(uint32_t img[mh][mw / LEDS_PER_COL])
{
  for (uint8_t i = 0; i < mh; i++)
  {
    for (uint8_t j = 0; j < mw; j++)
    {
      matrix->drawPixel(j, i, CRGB(img[i][j / LEDS_PER_COL]));
    }
  }
  matrix->show();
}
